def solution(target: int = 200, coins: list = None) -> int:
    """
    Generalized coin sum solution using recursion with memoization (top-down DP).
    """
    if coins is None:
        coins = [1, 2, 5, 10, 20, 50, 100, 200]

    memo = {}

    def count_ways(remaining, coin_idx):
        if remaining == 0: return 1
        if remaining < 0 or coin_idx >= len(coins): return 0

        state = (remaining, coin_idx)
        if state in memo:
            return memo[state]

        # Ways = (ways using at least one current coin) + (ways using only subsequent coins)
        res = count_ways(remaining - coins[coin_idx], coin_idx) + \
              count_ways(remaining, coin_idx + 1)

        memo[state] = res
        return res

    return count_ways(target, 0)


if __name__ == "__main__":
    print(solution(200))
